import { data, takaro } from '@takaro/helpers';
async function main() {
    const { gameServerId } = data;

    const gameServer = await takaro.gameserver.gameServerControllerGetOne(gameServerId);
    if (!gameServer.data.data.reachable) {
        return;
    }

    const serverName = gameServer.data.data.name;
    const userDiscord = data.module.userConfig.userDiscordChannel;
    const supportsInGameMessages = data.module.userConfig.supportsInGameMessages;
    const message = data.module.userConfig.message10Minute.replace(/\{server\}/g, serverName);

    await takaro.discord.discordControllerSendMessage(userDiscord, {
        message,
    });

    if (supportsInGameMessages) {
        await takaro.gameserver.gameServerControllerExecuteCommand(gameServerId, {
            command: `announce Shutdown | ${message}`,
        });
    }
}
await main();

